mapper.select:
SELECT /* 오늘 문의 */ (SELECT COUNT(*) FROM TB_BBS_PST WHERE DEL_YN = 'N' AND USE_YN = 'Y' AND BRD_CD = '3ccd942dfcbf11f08771908d6ec6e544' AND PST_LVL = 0 AND NOTICE_YN = 'N' AND DATE(RGT_DTM) = CURDATE() ) AS TODAY_CNT
/* 미답변 문의 */ , (SELECT COUNT(*) FROM TB_BBS_PST A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y' AND A.BRD_CD = '3ccd942dfcbf11f08771908d6ec6e544' AND A.PST_LVL = 0 AND A.NOTICE_YN = 'N' AND NOT EXISTS ( SELECT 1 FROM TB_BBS_PST R WHERE R.BRD_CD = A.BRD_CD AND R.ROT_PST_CD = A.PST_CD AND R.PST_LVL > 0 AND R.DEL_YN = 'N' AND R.USE_YN = 'Y' ) ) AS UNANSWERED_CNT
/* 이번달 문의 */ , (SELECT COUNT(*) FROM TB_BBS_PST WHERE DEL_YN = 'N' AND USE_YN = 'Y' AND BRD_CD = '3ccd942dfcbf11f08771908d6ec6e544' AND PST_LVL = 0 AND NOTICE_YN = 'N' AND DATE_FORMAT(RGT_DTM, '%Y%m') = DATE_FORMAT(NOW(), '%Y%m') ) AS MONTH_CNT
/* 전체 문의 */ , (SELECT COUNT(*) FROM TB_BBS_PST WHERE DEL_YN = 'N' AND USE_YN = 'Y' AND BRD_CD = '3ccd942dfcbf11f08771908d6ec6e544' AND PST_LVL = 0 AND NOTICE_YN = 'N' ) AS TOTAL_CNT
